#include <bits/stdc++.h>
using namespace std;
int main() {
    int a, b, n;
    cin >> a >> b >> n;
    int last = a + (n - 1) * b;
    int total = n * (a + last) / 2;
    cout << last << " " << total << endl;
    return 0;
}
```

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    int a[105];
    for (int i = 0; i < n; i++) cin >> a[i];
    int *p = a;
    int maxVal = *p, minVal = *p;
    for (int i = 1; i < n; i++) {
        if (*(p + i) > maxVal) maxVal = *(p + i);
        if (*(p + i) < minVal) minVal = *(p + i);
    }
    cout << maxVal << " " << minVal << endl;
    return 0;
}
```

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    int a[105];
    for (int i = 0; i < n; i++) cin >> a[i];
    int *p = a;
    for (int i = 0; i < n - 1; i++) {
        int minIdx = i;
        for (int j = i + 1; j < n; j++)
            if (*(p + j) < *(p + minIdx)) minIdx = j;
        if (minIdx != i) {
            int temp = *(p + i);
            *(p + i) = *(p + minIdx);
            *(p + minIdx) = temp;
        }
    }
    for (int i = 0; i < n; i++) {
        if (i > 0) cout << " ";
        cout << *(p + i);
    }
    cout << endl;
    return 0;
}
```
